head.script:
scwin.onpageload = function() {	

// .link 클릭 시 새창 열기
$(".link").on("click", function(e) {
  e.preventDefault();
  const url = `/websquare/websquare.html?w2xPath=/pub/${$(this).attr("target")}/${$(this).attr("name")}.xml`;

  const src = `pub/${$(this).attr("target")}/${$(this).attr("name")}.xml`;
   window.open(url, "_blank");
//$c.win.openMenu(src.substring(src.lastIndexOf("/")+1),src,src.substring(src.lastIndexOf("/")+1));
});

// name 값을 옆 td에 넣기
$(".link[name]").each(function() {
  $(this).closest("td").next("td").text($(this).attr("name"));
});

}
